INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 27, 2, 0, 16, 155, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ", "獣人族", 8, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", "人助け、応援", "東山奈央", 44, 100101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 5, 2, 0, 17, 158, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ", "ヒューマン", 4, "トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", "種田梨沙", 47, 100201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 12, 2, 0, 18, 163, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ", "魔族", 1, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", "早見沙織", 46, 100301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 10, 5, 0, 9, 128, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "ミソギ", "ヒューマン", 8, "リトルリリカル", "探検好きのイタズラっ子", "いたずら、探検", "諸星すみれ", 27, 100401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 25, 8, 0, 12, 146, "？？？", "マツリ", "獣人族", 11, "王宮騎士団（NIGHTMARE）", "ヒーローに憧れる騎士見習いの少女", "ヒーローごっこ", "下田麻美", 40, 100501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 22, 7, 0, 13, 150, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "アカリ", "魔族", 11, "悪魔偽王国軍（ディアボロス）", "甘え上手なみんなの人気者", "サックス", "浅倉杏美", 42, 100601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 23, 7, 0, 14, 130, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "ミヤコ", "魔族", 1, "悪魔偽王国軍（ディアボロス）", "プリン大好きゴースト娘", "プリンを食べること", "雨宮天", 32, 100701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 10, 15, 0, 14, 150, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ユキ", "エルフ", 10, "ヴァイスフリューゲル　ランドソル支部", "ボクは誰よりも美しい", "鏡で自分を見ること", "大空直美", 40, 100801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 5, 13, 0, 17, 159, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "アンナ", "魔族", 7, "トワイライトキャラバン", "前世を信じる中二病患者、「疾風の冥姫」", "小説執筆", "髙野麻美", 45, 100901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 22, 10, 0, 16, 155, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホ", "獣人族", 9, "自警団（カォン）", "マホマホ王国のプリンセス", "空想、ぬいぐるみ集め", "内田真礼", 42, 101001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 25, 3, 0, 15, 156, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "リノ", "ヒューマン", 8, "ラビリンス", "人懐っこくてマシンガントークな妹系少女", "お裁縫", "阿澄佳奈", 44, 101101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 24, 6, 0, 17, 156, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "ハツネ", "エルフ", 12, "フォレスティエ", "みんなのために超能力を使う眠り姫", "妹と遊ぶこと、二度寝、昼寝、早寝", "大橋彩香", 46, 101201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 21, 13, 0, 18, 166, "", "ナナカ", "魔族", 8, "トワイライトキャラバン", "オタク全開な魔法少女", "読書、魔法", "佳村はるか", 55, 101301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 3, 10, 0, 15, 152, "test", "カスミ", "獣人族", 11, "自警団（カォン）", "頭脳明晰な美少女名探偵", "読書、推理", "水瀬いのり", 41, 101401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 5, 6, 0, 21, 165, "test", "ミサト", "エルフ", 9, "フォレスティエ", "母性溢れる優しいみんなの「ミサト先生」", "絵本作り", "國府田マリ子", 54, 101501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 10, 14, 0, 17, 167, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "スズナ", "魔族", 4, "ルーセント学院", "天真爛漫で人気者のカリスマモデル", "ファッション", "上坂すみれ", 48, 101601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 7, 10, 0, 17, 158, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "カオリ", "獣人族", 7, "自警団（カォン）", "いつでも「なんくるないさ～」な天然娘", "踊り、空手", "高森奈津美", 53, 101701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 14, 14, 0, 23, 162, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "イオ", "魔族", 8, "ルーセント学院", "多くの男性を魅了する無垢な女教師", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "伊藤静", 52, 101801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 3, 5, 0, 10, 117, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "ミミ", "獣人族", 4, "リトルリリカル", "お歌もにんじんも、ウサギさんも大好き♪", "かわいいもの集め", "日高里菜", 21, 102001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 9, 9, 0, 12, 150, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "クルミ", "ヒューマン", 6, "サレンディア救護院", "泣き虫で臆病な守ってあげたい女の子", "観劇、おままごと", "植田佳奈", 40, 102101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 22, 7, 0, 13, 150, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "ヨリ", "魔族", 11, "悪魔偽王国軍（ディアボロス）", "人見知りであまのじゃくな女の子", "ゲーム全般", "原紗友里", 40, 102201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 10, 9, 0, 14, 148, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "アヤネ", "ヒューマン", 5, "サレンディア救護院", "ぷうきちといつも一緒！", "屋内でできる遊び", "芹澤優", 38, 102301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 12, 9, 0, 15, 154, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "スズメ", "ヒューマン", 12, "サレンディア救護院", "お嬢さまのためにがんばるドジっ娘メイド", "ご奉仕", "悠木碧", 43, 102501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 1, 11, 0, 17, 144, "test", "リン", "獣人族", 1, "牧場（エリザベスパーク）", "遊びと睡眠が何より大事なぐうたら娘", "あんパン", "小岩井ことり", 42, 102601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 30, 13, 0, 16, 154, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ", "魔族", 7, "トワイライトキャラバン", "運命の相手に一途すぎる乙女", "実験、裁縫、料理", "橋本ちなみ", 43, 102701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 4, 9, 0, 17, 156, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレン", "エルフ", 10, "サレンディア救護院", "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", "堀江由衣", 43, 102801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 24, 4, 0, 17, 157, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "ノゾミ", "ヒューマン", 1, "カルミナ", "歌って踊れる大人気アイドル", "舞台鑑賞、ダンス", "日笠陽子", 40, 102901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 31, 15, 0, 16, 163, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ニノン", "ヒューマン", 8, "ヴァイスフリューゲル　ランドソル支部", "トーゴクの神秘、オシエテクダサイ！", "忍法開発", "佐藤聡美", 51, 103001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 22, 7, 0, 18, 157, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ", "魔族", 12, "悪魔偽王国軍（ディアボロス）", "占いが得意な霊能少女", "占い", "大坪由佳", 42, 103101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 12, 12, 0, 18, 157, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "アキノ", "ヒューマン", 3, "メルクリウス財団", "一人前の商人を目指すパワフルお嬢様", "慈善事業", "松嵜麗", 45, 103201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 3, 11, 0, 20, 142, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "マヒル", "ヒューマン", 3, "牧場（エリザベスパーク）", "みんなを笑顔にするお笑い牧場主", "漫才", "新田恵海", 35, 103301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 16, 12, 0, 22, 164, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "ユカリ", "エルフ", 3, "メルクリウス財団", "純情でほっとけない大人の女性", "ウインドーショッピング", "今井麻美", 55, 103401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 2, 5, 0, 8, 118, "test", "キョウカ", "エルフ", 2, "リトルリリカル", "礼儀正しくしっかり者のちびっ子優等生", "お勉強", "小倉唯", 21, 103601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 11, 8, 0, 13, 149, "test", "トモ", "ヒューマン", 8, "王宮騎士団（NIGHTMARE）", "義理堅くてからかい好きな剣術少女", "剣術、年長者をからかう", "茅原実里", 43, 103701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 3, 11, 0, 14, 153, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "シオリ", "獣人族", 11, "牧場（エリザベスパーク）", "読書が趣味の病弱少女", "読書、お散歩", "小清水亜美", 40, 103801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 6, 6, 0, 13, 158, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "アオイ", "エルフ", 6, "フォレスティエ", "「友達」に憧れる、エルフの森の女の子", "友達作りのイメトレ", "花澤香菜", 44, 104001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 3, 4, 0, 17, 163, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ", "ヒューマン", 6, "カルミナ", "人々を守るために歌う、唱喚士の少女", "各種楽器", "福原綾香", 46, 104201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 9, 10, 0, 17, 168, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "マコト", "獣人族", 8, "自警団（カォン）", "男勝りで情に厚いワイルド娘", "お菓子作り", "小松未可子", 54, 104301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 5, 7, 0, "??", 172, "test", "イリヤ", "魔族", 5, "悪魔偽王国軍（ディアボロス）", "かつては夜を支配した最強の吸血鬼", "世界征服", "丹下桜", 50, 104401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 19, 15, 0, 18, 157, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ", "ヒューマン", 11, "ヴァイスフリューゲル　ランドソル支部", "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", "長妻樹里", 49, 104501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 1, 12, 0, 19, 158, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ", "獣人族", 3, "メルクリウス財団", "弱きを助け強きをくじく猫娘", "猫とたわむれること", "沼倉愛美", 48, 104601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 25, 8, 0, 25, 171, "？？？", "ジュン", "ヒューマン", 10, "王宮騎士団（NIGHTMARE）", "素顔を見せない冷静沈着な女性騎士", "格闘技、湯浴み", "川澄綾子", 50, 104701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 11, 12, 0, 20, 163, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ", "ヒューマン", 11, "メルクリウス財団", "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", "田所あずさ", 49, 104801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 24, 3, 0, 18, 168, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル", "ヒューマン", 10, "ラビリンス", "お姉ちゃんがお世話してあげるからねっ！", "家事全般", "生天目仁美", 54, 104901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 3, 14, 0, 11, 120, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ミサキ", "魔族", 1, "ルーセント学院", "ちょっとおませな恋に恋する女の子", "ファッション誌鑑賞、コスメ集め", "久野美咲", 22, 105001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 7, 13, 0, 27, 166, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "ミツキ", "ヒューマン", 3, "トワイライトキャラバン", "実験が趣味の危険な科学者", "研究、実験", "三石琴乃", 53, 105101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 14, 11, 0, 17, 150, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "リマ", "獣人族", 3, "牧場（エリザベスパーク）", "乙女チックなもふもふアニマル", "毛繕い、お喋り", "徳井青空", 100, 105201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 28, 15, 0, 17, 140, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "モニカ", "ヒューマン", 7, "ヴァイスフリューゲル　ランドソル支部", "見た目も中身もお子ちゃまな異国の軍人", "お菓子屋通い", "辻あゆみ", 33, 105301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 7, 4, 0, 14, 153, "test", "ツムギ", "ヒューマン", 9, "カルミナ", "ファッション大好きなキュートガール", "裁縫", "木戸衣吹", 45, 105401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 7, 15, 0, 16, 155, "test", "アユミ", "エルフ", 4, "ヴァイスフリューゲル　ランドソル支部", "どこまでも一途に慕う、純情乙女", "観察", "大関英里", 43, 105501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 11, 13, 0, 25, 167, "test", "ルカ", "ヒューマン", 7, "トワイライトキャラバン", "人情味溢れる粋でいなせな「姉御」", "釣り", "佐藤利奈", 54, 105601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 10, "", 0, 17, 156, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "ジータ", "ヒューマン", 3, "？？？", "空への冒険を夢見る騎空士の少女", "冒険、おしゃべり", "金元寿子", 45, 105701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 31, 1, 0, 17, 156, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "ペコリーヌ", "ヒューマン", 3, "美食殿", "いつも元気な腹ペコ少女", "食べ歩き、料理", "M・A・O", 46, 105801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 11, 1, 0, 11, 140, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "コッコロ", "エルフ", 5, "美食殿", "主を慕う、小さなガイド役", "瞑想、動植物の飼育", "伊藤美来", 35, 105901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 2, 1, 0, 14, 152, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "キャル", "獣人族", 9, "美食殿", "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", "立花理香", 39, 106001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 11, "", 0, 16, 148, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "ムイミ", "ヒューマン", 8, "？？？", "さまよえる謎の少女", "冒険、思い出話", "潘めぐみ", 40, 106101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 17, "", 0, 15, 155, "", "アリサ", "エルフ", 6, "？？？", "森番を目指すエルフの少女", "キレイな葉っぱを集めること", "優木かな", 42, 106301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 14, 1, 0, 14, 147, "", "シェフィ", "ドラゴン族", 12, "美食殿", "記憶喪失のドラゴン娘", "読書、ストレッチ", "近藤玲奈", "???", 106401);
