INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 29, 17, 0, 13, 145, "", "イノリ", "ドラゴン族", 9, "ドラゴンズネスト", "口が達者なヘタレドラゴン", "ゲーム", "藤田茜", "???", 106601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 17, 17, 0, 25, 168, "", "ホマレ", "ドラゴン族", 4, "ドラゴンズネスト", "妖しい微笑で全てを見透かす臥竜の頭領", "絵画、読書", "大西沙織", "???", 106701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 25, 3, 0, 25, 160, "", "ラビリスタ", "ヒューマン", 7, "ラビリンス", "秘密結社ラビリンスの『迷宮女王』", "人間観察", "沢城みゆき", "??", 106801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 1, "", 0, 29, 166, "", "カイザーインサイト", "獣人族", 7, "？？？", "謎に包まれたランドソルの主", "占い、支配", "蒼井翔太", "??", 106901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 24, "", 0, 24, 149, "", "ネネカ", "エルフ", 3, "？？？", "研究所に隠れ住む物静かなお姉さん", "物真似、芸術鑑賞", "井口裕香", "??", 107001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 7, 8, 0, 27, 165, "", "クリスティーナ", "ヒューマン", 2, "王宮騎士団（NIGHTMARE）", "傍若無人な王宮騎士団副団長", "強敵との闘争", "たかはし智秋", "??", 107101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 31, 1, 0, 17, 156, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "ペコリーヌ（サマー）", "ヒューマン", 3, "美食殿", "いつも元気な腹ペコ少女", "食べ歩き、料理", "M・A・O", 46, 107501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 11, 1, 0, 11, 140, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "コッコロ（サマー）", "エルフ", 5, "美食殿", "主を慕う、小さなガイド役", "瞑想、動植物の飼育", "伊藤美来", 35, 107601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 12, 9, 0, 15, 154, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "スズメ（サマー）", "ヒューマン", 12, "サレンディア救護院", "お嬢さまのためにがんばるドジっ娘メイド", "ご奉仕", "悠木碧", 43, 107701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 2, 1, 0, 14, 152, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "キャル（サマー）", "獣人族", 9, "美食殿", "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", "立花理香", 39, 107801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 1, 12, 0, 19, 158, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ（サマー）", "獣人族", 3, "メルクリウス財団", "弱きを助け強きをくじく猫娘", "猫とたわむれること", "沼倉愛美", 48, 107901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 11, 12, 0, 20, 163, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ（サマー）", "ヒューマン", 11, "メルクリウス財団", "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", "田所あずさ", 49, 108001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 22, 7, 0, 18, 157, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ（ハロウィン）", "魔族", 12, "悪魔偽王国軍（ディアボロス）", "占いが得意な霊能少女", "占い", "大坪由佳", 42, 108101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 23, 7, 0, 14, 130, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "ミヤコ（ハロウィン）", "魔族", 1, "悪魔偽王国軍（ディアボロス）", "プリン大好きゴースト娘", "プリンを食べること", "雨宮天", 32, 108201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 3, 14, 0, 11, 120, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ミサキ（ハロウィン）", "魔族", 1, "ルーセント学院", "ちょっとおませな恋に恋する女の子", "ファッション誌鑑賞、コスメ集め", "久野美咲", 22, 108301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 3, 4, 0, 17, 163, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ（クリスマス）", "ヒューマン", 6, "カルミナ", "人々を守るために歌う、唱喚士の少女", "各種楽器", "福原綾香", 46, 108401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 9, 9, 0, 12, 150, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "クルミ（クリスマス）", "ヒューマン", 6, "サレンディア救護院", "泣き虫で臆病な守ってあげたい女の子", "観劇、おままごと", "植田佳奈", 40, 108501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 10, 9, 0, 14, 148, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "アヤネ（クリスマス）", "ヒューマン", 5, "サレンディア救護院", "ぷうきちといつも一緒！", "屋内でできる遊び", "芹澤優", 38, 108601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 27, 2, 0, 16, 155, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ（ニューイヤー）", "獣人族", 8, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", "人助け、応援", "東山奈央", 44, 108701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 5, 2, 0, 17, 158, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ（ニューイヤー）", "ヒューマン", 4, "トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", "種田梨沙", 47, 108801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 12, 2, 0, 18, 163, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ（ニューイヤー）", "魔族", 1, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", "早見沙織", 46, 108901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 30, 13, 0, 16, 154, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ（バレンタイン）", "魔族", 7, "トワイライトキャラバン", "運命の相手に一途すぎる乙女", "実験、裁縫、料理", "橋本ちなみ", 43, 109001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 24, 3, 0, 18, 168, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル（バレンタイン）", "ヒューマン", 10, "ラビリンス", "お姉ちゃんがお世話してあげるからねっ！", "家事全般", "生天目仁美", 54, 109101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 1, "", 0, 17, 156, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "アン", "ヒューマン", 12, "？？？", "英霊と契約を結んだマナリアの天才王女", "読書", "日笠陽子", 55, 109201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 4, "", 0, 16, 144, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "ルゥ", "ヒューマン", 2, "？？？", "マナリア魔法学院の新入生", "食べること、眠ること", "こやまきみこ", 45, 109301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 3, "", 0, 17, 167, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "グレア", "半人半竜", 11, "？？？", "人を超越した力を有す心優しい竜姫", "ピアノ", "福原綾香", 67, 109401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 19, 15, 0, 18, 157, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ（オーエド）", "ヒューマン", 11, "ヴァイスフリューゲル　ランドソル支部", "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", "長妻樹里", 49, 109501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 31, 15, 0, 16, 163, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ニノン（オーエド）", "ヒューマン", 8, "ヴァイスフリューゲル　ランドソル支部", "トーゴクの神秘、オシエテクダサイ！", "忍法開発", "佐藤聡美", 51, 109601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("?", 2, "", 0, 17, 154, "", "レム", "鬼族", 2, "？？？", "鬼がかりの万能妹メイド", "演劇鑑賞、詩文", "水瀬いのり", "??", 109701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("?", 2, "", 0, 17, 154, "", "ラム", "鬼族", 2, "？？？", "毒舌系鬼姉メイド", "読書", "村川梨衣", "??", 109801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("?", 23, "", 0, "??", 164, "", "エミリア", "ハーフエルフ", 9, "？？？", "銀髪のおっとりハーフエルフ", "パックの毛繕い、勉強", "高橋李依", "??", 109901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 10, 14, 0, 17, 167, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "スズナ（サマー）", "魔族", 4, "ルーセント学院", "天真爛漫で人気者のカリスマモデル", "ファッション", "上坂すみれ", 48, 110001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 14, 14, 0, 23, 162, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "イオ（サマー）", "魔族", 8, "ルーセント学院", "多くの男性を魅了する無垢な女教師", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "伊藤静", 52, 110101);
