INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 9, 10, 0, 17, 168, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "マコト（サマー）", "獣人族", 8, "自警団（カォン）", "男勝りで情に厚いワイルド娘", "お菓子作り", "小松未可子", 54, 110401);
