INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 22, 10, 0, 16, 155, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホ（サマー）", "獣人族", 9, "自警団（カォン）", "マホマホ王国のプリンセス", "空想、ぬいぐるみ集め", "内田真礼", 42, 110601);
