INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 11, 13, 0, 25, 167, "", "ルカ（サマー）", "ヒューマン", 7, "トワイライトキャラバン", "人情味溢れる粋でいなせな「姉御」", "釣り", "佐藤利奈", 54, 113101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 5, 13, 0, 17, 159, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "アンナ（サマー）", "魔族", 7, "トワイライトキャラバン", "前世を信じる中二病患者、「疾風の冥姫」", "小説執筆", "髙野麻美", 45, 113201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 21, 13, 0, 18, 166, "", "ナナカ（サマー）", "魔族", 8, "トワイライトキャラバン", "オタク全開な魔法少女", "読書、魔法", "佳村はるか", 55, 113301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 24, 6, 0, 17, 156, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "ハツネ（サマー）", "エルフ", 12, "フォレスティエ", "みんなのために超能力を使う眠り姫", "妹と遊ぶこと、二度寝、昼寝、早寝", "大橋彩香", 46, 113401);
