INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 25, 8, 0, 25, 171, "", "ジュン（サマー）", "ヒューマン", 10, "王宮騎士団（NIGHTMARE）", "素顔を見せない冷静沈着な女性騎士", "格闘技、湯浴み", "川澄綾子", 50, 113601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 22, 7, 0, 13, 150, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "アカリ（エンジェル）", "魔族", 11, "悪魔偽王国軍（ディアボロス）", "甘え上手なみんなの人気者", "サックス", "浅倉杏美", 42, 113701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 22, 7, 0, 13, 150, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "ヨリ（エンジェル）", "魔族", 11, "悪魔偽王国軍（ディアボロス）", "人見知りであまのじゃくな女の子", "ゲーム全般", "原紗友里", 40, 113801);
