INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 12, 2, 0, 18, 163, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ（ハロウィン）", "魔族", 1, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", "早見沙織", 46, 114001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 25, 8, 0, 12, 146, "", "マツリ（ハロウィン）", "獣人族", 11, "王宮騎士団（NIGHTMARE）", "ヒーローに憧れる騎士見習いの少女", "ヒーローごっこ", "下田麻美", 40, 114101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 28, 15, 0, 17, 140, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "モニカ（マジカル）", "ヒューマン", 7, "ヴァイスフリューゲル　ランドソル支部", "見た目も中身もお子ちゃまな異国の軍人", "お菓子屋通い", "辻あゆみ", 33, 114201);
