INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 12, 12, 0, 18, 157, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "アキノ（クリスマス）", "ヒューマン", 3, "メルクリウス財団", "一人前の商人を目指すパワフルお嬢様", "慈善事業", "松嵜麗", 45, 114401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 4, 9, 0, 17, 156, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレン（クリスマス）", "エルフ", 10, "サレンディア救護院", "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", "堀江由衣", 43, 114501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 16, 12, 0, 22, 164, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "ユカリ（クリスマス）", "エルフ", 3, "メルクリウス財団", "純情でほっとけない大人の女性", "ウインドーショッピング", "今井麻美", 55, 114601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 11, "", 0, 16, 148, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "ムイミ（ニューイヤー）", "ヒューマン", 8, "？？？", "さまよえる謎の少女", "冒険、思い出話", "潘めぐみ", 40, 114701);
