INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 1, 12, 0, 19, 158, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ（作業服）", "獣人族", 3, "メルクリウス財団", "弱きを助け強きをくじく猫娘", "猫とたわむれること", "沼倉愛美", 48, 116801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 11, 12, 0, 20, 163, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ（作業服）", "ヒューマン", 11, "メルクリウス財団", "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", "田所あずさ", 49, 116901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 30, 13, 0, 16, 154, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ（サマー）", "魔族", 7, "トワイライトキャラバン", "運命の相手に一途すぎる乙女", "実験、裁縫、料理", "橋本ちなみ", 43, 117001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 24, 3, 0, 18, 168, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル（サマー）", "ヒューマン", 10, "ラビリンス", "お姉ちゃんがお世話してあげるからねっ！", "家事全般", "生天目仁美", 54, 117101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 24, 4, 0, 17, 157, "", "ノゾミ（サマー）", "ヒューマン", 1, "カルミナ", "歌って踊れる大人気アイドル", "舞台鑑賞、ダンス", "日笠陽子", 40, 117201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 3, 4, 0, 17, 163, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ（サマー）", "ヒューマン", 6, "カルミナ", "人々を守るために歌う、唱喚士の少女", "各種楽器", "福原綾香", 46, 117301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 7, 4, 0, 14, 153, "", "ツムギ（サマー）", "ヒューマン", 9, "カルミナ", "ファッション大好きなキュートガール", "裁縫", "木戸衣吹", 45, 117401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 7, 13, 0, 27, 166, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "ミツキ（オーエド）", "ヒューマン", 3, "トワイライトキャラバン", "実験が趣味の危険な科学者", "研究、実験", "三石琴乃", 53, 117501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 10, 15, 0, 14, 150, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ユキ（オーエド）", "エルフ", 10, "ヴァイスフリューゲル　ランドソル支部", "ボクは誰よりも美しい", "鏡で自分を見ること", "大空直美", 40, 117601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 7, 10, 0, 17, 158, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "カオリ（ハロウィン）", "獣人族", 7, "自警団（カォン）", "いつでも「なんくるないさ～」な天然娘", "踊り、空手", "高森奈津美", 53, 117701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 31, 15, 0, 16, 163, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ニノン（ハロウィン）", "ヒューマン", 8, "ヴァイスフリューゲル　ランドソル支部", "トーゴクの神秘、オシエテクダサイ！", "忍法開発", "佐藤聡美", 51, 117801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 10, 14, 0, 17, 167, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "スズナ（ハロウィン）", "魔族", 4, "ルーセント学院", "天真爛漫で人気者のカリスマモデル", "ファッション", "上坂すみれ", 48, 117901);
