INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 16, 12, 0, 22, 164, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "ユカリ（キャンプ）", "エルフ", 3, "メルクリウス財団", "純情でほっとけない大人の女性", "ウインドーショッピング", "今井麻美", 55, 122201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 6, "", 0, "??", 149, "", "ヴァンピィ", "魔族", 12, "？？？", "けんぞくのご主人様", "お散歩、お料理", "釘宮理恵", 41, 122301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 27, 2, 0, 16, 155, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ（サマー）", "獣人族", 8, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", "人助け、応援", "東山奈央", 44, 122401);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 12, 2, 0, 18, 163, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ（サマー）", "魔族", 1, "トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", "早見沙織", 46, 122501);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 5, 2, 0, 17, 158, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ（サマー）", "ヒューマン", 4, "トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", "種田梨沙", 47, 122601);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 2, 5, 0, 8, 118, "", "キョウカ（サマー）", "エルフ", 2, "リトルリリカル", "礼儀正しくしっかり者のちびっ子優等生", "お勉強", "小倉唯", 21, 122701);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 10, 5, 0, 9, 128, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "ミソギ（サマー）", "ヒューマン", 8, "リトルリリカル", "探検好きのイタズラっ子", "いたずら、探検", "諸星すみれ", 27, 122801);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 3, 5, 0, 10, 117, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "ミミ（サマー）", "獣人族", 4, "リトルリリカル", "お歌もにんじんも、ウサギさんも大好き♪", "かわいいもの集め", "日高里菜", 21, 122901);
