INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("B", 10, 9, 0, 14, 148, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "アヤネ（エクスプローラー）", "ヒューマン", 5, "サレンディア救護院", "ぷうきちといつも一緒！", "屋内でできる遊び", "芹澤優", 38, 123201);
