INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 22, 7, 0, 13, 150, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "ヨリ（クリスマス）", "魔族", 11, "悪魔偽王国軍（ディアボロス）", "人見知りであまのじゃくな女の子", "ゲーム全般", "原紗友里", 40, 124101);
