INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 3, 11, 0, 14, 153, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "シオリ（レンジャー）", "獣人族", 11, "牧場（エリザベスパーク）", "読書が趣味の病弱少女", "読書、お散歩", "小清水亜美", 40, 125401);
