INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 28, 19, 0, 20, 165, "", "ランファ（サマー）", "魔族", 12, "レイジ・レギオン", "静寂を求め歌う陰気少女", "歌、読書、詩を書くこと", "原田彩楓", 53, 126901);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 19, 15, 0, 18, 157, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ（サマー）", "ヒューマン", 11, "ヴァイスフリューゲル　ランドソル支部", "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", "長妻樹里", 49, 127001);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("AB", 22, 7, 0, 18, 157, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ（サマー）", "魔族", 12, "悪魔偽王国軍（ディアボロス）", "占いが得意な霊能少女", "占い", "大坪由佳", 42, 127101);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 2, 1, 0, 14, 152, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "キャル（編入生）", "獣人族", 9, "美食殿", "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", "立花理香", 39, 127201);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("O", 10, 14, 0, 17, 167, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "スズナ（編入生）", "魔族", 4, "ルーセント学院", "天真爛漫で人気者のカリスマモデル", "ファッション", "上坂すみれ", 48, 127301);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 4, 9, 0, 17, 156, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレン（サラサリア）", "エルフ", 10, "サレンディア救護院", "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", "堀江由衣", 43, 127501);
