INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("A", 27, 2, 0, 16, 155, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ（アストラル）", "獣人族", 8, "トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", "人助け、応援", "東山奈央", 44, 128701);
